-- ============================================================================
-- Alfa Informática — Seed inicial (migra os dados que hoje estão em
-- products.js / categories.js para o banco real). Rode DEPOIS do schema.sql,
-- uma única vez, no SQL Editor do Supabase.
-- Idempotente: pode rodar de novo sem duplicar (usa "on conflict do nothing").
-- ============================================================================

create unique index if not exists products_codigo_interno_key on public.products (codigo_interno);

