  ('perifericos','mouse','Mouse',1),('perifericos','mousepad','Mousepad',2),('perifericos','teclados','Teclados',3),('perifericos','headsets','Headsets',4),('perifericos','fones','Fones de Ouvido',5),('perifericos','microfones','Microfones',6),('perifericos','webcam','Webcam',7),
