-- ── PRODUTOS ─────────────────────────────────────────────────────────────
insert into public.products (codigo_interno, name, brand, price, old_price, subcategory_id, category_id, stock, rating, reviews_count, images, description, specs)
select 'LEGACY-'||v.legacy_id, v.name, v.brand, v.price, v.old_price, sc.id, sc.categoria_id, v.stock, v.rating, v.reviews_count, '["img teste.jpg"]'::jsonb, v.description, v.specs::jsonb
from (values
(1,'Intel Core i9-14900K 3.2GHz 24-Core LGA1700','Intel',2799,3199,'processadores',8,4.9,312,'O <strong>Intel Core i9-14900K</strong> é o processador topo de linha da 14ª geração Raptor Lake Refresh. Com 24 núcleos (8P+16E), 32 threads e turbo de até 6.0 GHz, entrega performance extrema para jogos AAA, criação de conteúdo 3D, edição de vídeo 4K e multitarefa pesada. Compatível com as principais placas Z790 e B760.','[["Fabricante","Intel"],["Socket","LGA1700"],["Geração","14ª (Raptor Lake Refresh)"],["Núcleos P-Core","8"],["Núcleos E-Core","16"],["Total de Núcleos","24"],["Threads","32"],["Clock Base","3.2 GHz"],["Clock Turbo Máx.","6.0 GHz"],["Cache L3","36 MB"],["TDP Base","125 W"],["TDP Máximo","253 W"],["Gráfico Integrado","Intel UHD 770"],["Cooler Incluso","Não"],["Memória Suportada","DDR4 / DDR5"]]'),
(2,'AMD Ryzen 9 7950X 4.5GHz 16-Core AM5','AMD',3299,3799,'processadores',5,4.8,197,'O <strong>AMD Ryzen 9 7950X</strong> é o processador de workstation da plataforma AM5, com 16 núcleos Zen 4 e frequência turbo de 5.7 GHz. Ideal para renderização 3D, compilação, edição profissional e criação de conteúdo de alta demanda. Suporta DDR5 e PCIe 5.0.','[["Fabricante","AMD"],["Socket","AM5"],["Arquitetura","Zen 4"],["Núcleos","16"],["Threads","32"],["Clock Base","4.5 GHz"],["Clock Turbo Máx.","5.7 GHz"],["Cache L3","64 MB"],["TDP","170 W"],["Gráfico Integrado","AMD Radeon (RDNA 2)"],["Cooler Incluso","Não"],["Memória Suportada","DDR5"]]'),
(3,'Intel Core i7-14700K 3.4GHz 20-Core LGA1700','Intel',1899,2199,'processadores',14,4.8,241,'O <strong>Intel Core i7-14700K</strong> oferece 20 núcleos (8P+12E) e turbo de até 5.6 GHz, equilibrando performance extrema em jogos e produtividade. Perfeito para setups gamers de alto nível com custo-benefício superior ao i9.','[["Fabricante","Intel"],["Socket","LGA1700"],["Geração","14ª (Raptor Lake Refresh)"],["Núcleos P-Core","8"],["Núcleos E-Core","12"],["Total de Núcleos","20"],["Threads","28"],["Clock Base","3.4 GHz"],["Clock Turbo Máx.","5.6 GHz"],["Cache L3","33 MB"],["TDP Base","125 W"],["TDP Máximo","253 W"],["Gráfico Integrado","Intel UHD 770"],["Cooler Incluso","Não"]]'),
(4,'AMD Ryzen 5 7600X 4.7GHz 6-Core AM5','AMD',1099,1299,'processadores',22,4.7,408,'O <strong>AMD Ryzen 5 7600X</strong> é a escolha ideal para gamers que buscam máximo FPS com custo acessível. Com 6 núcleos Zen 4 e turbo de 5.3 GHz, supera gerações anteriores na maioria dos títulos AAA.','[["Fabricante","AMD"],["Socket","AM5"],["Arquitetura","Zen 4"],["Núcleos","6"],["Threads","12"],["Clock Base","4.7 GHz"],["Clock Turbo Máx.","5.3 GHz"],["Cache L3","32 MB"],["TDP","105 W"],["Gráfico Integrado","AMD Radeon (RDNA 2)"],["Cooler Incluso","Não"],["Memória Suportada","DDR5"]]'),
(5,'Intel Core i5-14600K 3.5GHz 14-Core LGA1700','Intel',1249,1499,'processadores',19,4.8,531,'O <strong>Intel Core i5-14600K</strong> é o rei do custo-benefício para gaming. Com 14 núcleos (6P+8E) e turbo de 5.3 GHz, entrega performance que rivaliza com gerações anteriores de i9 a um preço muito mais acessível.','[["Fabricante","Intel"],["Socket","LGA1700"],["Geração","14ª (Raptor Lake Refresh)"],["Núcleos P-Core","6"],["Núcleos E-Core","8"],["Total de Núcleos","14"],["Threads","20"],["Clock Base","3.5 GHz"],["Clock Turbo Máx.","5.3 GHz"],["Cache L3","24 MB"],["TDP Base","125 W"],["Gráfico Integrado","Intel UHD 770"],["Cooler Incluso","Não"]]'),
(6,'NVIDIA GeForce RTX 4090 24GB GDDR6X','NVIDIA',9999,11999,'placas-de-video',3,5.0,178,'A <strong>NVIDIA GeForce RTX 4090</strong> é a placa de vídeo mais poderosa do mercado para consumidores. Com 24 GB GDDR6X, arquitetura Ada Lovelace e suporte a Ray Tracing de 3ª geração, DLSS 3 com Frame Generation e AV1 encode/decode duplo. Domina qualquer jogo em 4K com raytracing ativado.','[["Fabricante","NVIDIA"],["Chipset","GeForce RTX 4090"],["Arquitetura","Ada Lovelace"],["VRAM","24 GB GDDR6X"],["Barramento de Memória","384-bit"],["Clock GPU Base","2235 MHz"],["Clock GPU Boost","2520 MHz"],["CUDA Cores","16.384"],["TDP","450 W"],["Saídas de Vídeo","3x DisplayPort 1.4a, 1x HDMI 2.1"],["Resolução Máxima","8K"],["DirectX","12 Ultimate"],["Comprimento","336 mm"]]'),
(7,'AMD Radeon RX 7900 XTX 24GB GDDR6','AMD',5999,7299,'placas-de-video',4,4.8,134,'A <strong>AMD Radeon RX 7900 XTX</strong> é a placa topo de linha da AMD com 24 GB GDDR6 e arquitetura RDNA 3. Excelente para 4K gaming, edição de vídeo e ray tracing, com suporte a DisplayPort 2.1 para monitores 8K.','[["Fabricante","AMD"],["Chipset","Radeon RX 7900 XTX"],["Arquitetura","RDNA 3"],["VRAM","24 GB GDDR6"],["Barramento de Memória","384-bit"],["Clock GPU Base","1855 MHz"],["Clock GPU Boost","2500 MHz"],["Compute Units","96"],["TDP","355 W"],["Saídas de Vídeo","2x DisplayPort 2.1, 1x HDMI 2.1, 1x USB-C"],["DirectX","12 Ultimate"],["Comprimento","287 mm"]]'),
(8,'NVIDIA GeForce RTX 4070 Ti 12GB GDDR6X','NVIDIA',4199,4999,'placas-de-video',7,4.7,209,'A <strong>NVIDIA GeForce RTX 4070 Ti</strong> com 12 GB GDDR6X entrega performance de 4K gaming a um preço mais acessível que o topo de linha. Suporte completo a DLSS 3, Ray Tracing e AV1.','[["Fabricante","NVIDIA"],["Chipset","GeForce RTX 4070 Ti"],["Arquitetura","Ada Lovelace"],["VRAM","12 GB GDDR6X"],["Barramento de Memória","192-bit"],["Clock GPU Boost","2610 MHz"],["CUDA Cores","7.680"],["TDP","285 W"],["Saídas de Vídeo","3x DisplayPort 1.4a, 1x HDMI 2.1"],["DirectX","12 Ultimate"]]'),
(9,'NVIDIA GeForce RTX 4060 8GB GDDR6','NVIDIA',1999,2399,'placas-de-video',18,4.6,387,'A <strong>NVIDIA GeForce RTX 4060</strong> com 8 GB GDDR6 é ideal para gaming em 1080p com ray tracing e DLSS 3. Ótimo custo-benefício para quem quer entrar na geração Ada Lovelace.','[["Fabricante","NVIDIA"],["Chipset","GeForce RTX 4060"],["Arquitetura","Ada Lovelace"],["VRAM","8 GB GDDR6"],["Barramento de Memória","128-bit"],["Clock GPU Boost","2460 MHz"],["CUDA Cores","3.072"],["TDP","115 W"],["Saídas de Vídeo","3x DisplayPort 1.4a, 1x HDMI 2.1"],["DirectX","12 Ultimate"]]'),
(10,'AMD Radeon RX 7600 8GB GDDR6','AMD',1399,1699,'placas-de-video',11,4.5,198,'A <strong>AMD Radeon RX 7600</strong> com 8 GB GDDR6 e arquitetura RDNA 3 entrega excelente performance em 1080p com suporte a ray tracing e FSR 3.','[["Fabricante","AMD"],["Chipset","Radeon RX 7600"],["Arquitetura","RDNA 3"],["VRAM","8 GB GDDR6"],["Barramento de Memória","128-bit"],["Clock GPU Boost","2655 MHz"],["Compute Units","32"],["TDP","165 W"],["Saídas de Vídeo","1x DisplayPort 2.1, 1x HDMI 2.1, 2x DisplayPort 1.4"]]'),
(11,'Corsair Vengeance 32GB DDR5 6000MHz Kit (2x16GB)','Corsair',699,849,'memorias-ram',23,4.8,241,'O kit <strong>Corsair Vengeance DDR5 32 GB 6000 MHz</strong> oferece performance DDR5 de alto nível com latências otimizadas para plataformas Intel e AMD AM5. Com XMP 3.0 e EXPO para overclock automático.','[["Fabricante","Corsair"],["Tipo","DDR5"],["Capacidade","32 GB (2x 16 GB)"],["Frequência","6000 MHz"],["Latência","CL36-36-36-76"],["Tensão","1.35 V"],["Perfil XMP","XMP 3.0"],["Perfil EXPO","Sim"],["Altura","34 mm"],["Garantia","Lifetime"]]'),
(12,'Kingston Fury Beast 16GB DDR4 3200MHz','Kingston',289,349,'memorias-ram',35,4.7,512,'O <strong>Kingston Fury Beast DDR4 16 GB 3200 MHz</strong> é a memória DDR4 com melhor custo-benefício do mercado. Compatível com Intel XMP 2.0, plug-and-play em qualquer plataforma LGA1200/LGA1700 com suporte a DDR4.','[["Fabricante","Kingston"],["Tipo","DDR4"],["Capacidade","16 GB (1x 16 GB)"],["Frequência","3200 MHz"],["Latência","CL16"],["Tensão","1.35 V"],["Perfil XMP","XMP 2.0"],["Altura","34.1 mm"],["Garantia","Lifetime"]]'),
(13,'HyperX Fury 32GB DDR4 3600MHz Kit (2x16GB)','HyperX',399,479,'memorias-ram',17,4.7,189,'O kit <strong>HyperX Fury DDR4 32 GB 3600 MHz</strong> oferece excelente desempenho para gamers e criadores de conteúdo na plataforma DDR4, com compatibilidade automática via XMP 2.0.','[["Fabricante","HyperX (Kingston)"],["Tipo","DDR4"],["Capacidade","32 GB (2x 16 GB)"],["Frequência","3600 MHz"],["Latência","CL17"],["Tensão","1.35 V"],["Perfil XMP","XMP 2.0"],["Garantia","Lifetime"]]'),
(14,'Samsung 990 Pro 2TB NVMe PCIe 4.0 M.2','Samsung',799,999,'ssd-hd',9,4.9,408,'O <strong>Samsung 990 Pro 2 TB NVMe PCIe 4.0</strong> é um dos SSDs mais rápidos disponíveis, com leitura sequencial de 7.450 MB/s e escrita de 6.900 MB/s. Ideal para sistemas de criação profissional, jogos de alta demanda e workstations.','[["Fabricante","Samsung"],["Capacidade","2 TB"],["Interface","NVMe PCIe 4.0 x4"],["Form Factor","M.2 2280"],["Leitura Sequencial","7.450 MB/s"],["Escrita Sequencial","6.900 MB/s"],["IOPS Leitura","1.400.000"],["IOPS Escrita","1.550.000"],["Controlador","Samsung Elpis"],["Flash NAND","Samsung V-NAND TLC"],["Garantia","5 anos"]]'),
(15,'Kingston NV2 1TB NVMe M.2 PCIe 4.0','Kingston',299,379,'ssd-hd',41,4.6,634,'O <strong>Kingston NV2 1 TB NVMe PCIe 4.0</strong> é o SSD de entrada com excelente custo-benefício. Com leitura de até 3.500 MB/s, é ideal para quem quer sair do HD mecânico sem gastar muito.','[["Fabricante","Kingston"],["Capacidade","1 TB"],["Interface","NVMe PCIe 4.0 x4"],["Form Factor","M.2 2280"],["Leitura Sequencial","3.500 MB/s"],["Escrita Sequencial","2.800 MB/s"],["Garantia","3 anos"]]'),
(16,'Seagate Barracuda 2TB HD 7200RPM SATA','Seagate',239,299,'ssd-hd',28,4.4,823,'O <strong>Seagate Barracuda 2 TB</strong> é o HD mecânico mais vendido do mercado, com 7.200 RPM e cache de 256 MB. Ideal para armazenamento de mídia, backups e arquivos em geral.','[["Fabricante","Seagate"],["Capacidade","2 TB"],["Interface","SATA 6 Gb/s"],["Velocidade de Rotação","7.200 RPM"],["Cache","256 MB"],["Form Factor","3.5\""],["Garantia","2 anos"]]'),
(17,'ASUS ROG Strix B650-E Gaming WiFi DDR5','ASUS',1599,1899,'placas-mae',6,4.8,156,'A <strong>ASUS ROG Strix B650-E Gaming WiFi</strong> é uma placa-mãe premium para a plataforma AM5 com suporte a DDR5 até 6400+ MHz, Wi-Fi 6E, PCIe 5.0 e M.2 PCIe 5.0 para os SSDs mais rápidos.','[["Fabricante","ASUS"],["Chipset","AMD B650E"],["Socket","AM5"],["Form Factor","ATX"],["Memória","4x DDR5, até 128 GB"],["Freq. Memória Suportada","até 6400+ MHz (OC)"],["Slots PCIe","1x PCIe 5.0 x16, 1x PCIe 4.0 x16"],["Slots M.2","4x (1x PCIe 5.0, 3x PCIe 4.0)"],["USB Traseiro","2x USB4, 4x USB 3.2 Gen2, 2x USB 2.0"],["Rede","2.5GbE Intel"],["Wi-Fi","Wi-Fi 6E"],["Áudio","Realtek ALC4082"]]'),
(18,'MSI MAG B650 TOMAHAWK WiFi DDR5','MSI',1099,1299,'placas-mae',10,4.7,213,'A <strong>MSI MAG B650 TOMAHAWK WiFi</strong> é uma placa-mãe custo-benefício para AMD AM5 com DDR5, Wi-Fi 6E, PCIe 5.0 e VRM robusto para overclock moderado do Ryzen 7000.','[["Fabricante","MSI"],["Chipset","AMD B650"],["Socket","AM5"],["Form Factor","ATX"],["Memória","4x DDR5, até 128 GB"],["Slots M.2","3x PCIe 4.0"],["Rede","2.5GbE Realtek"],["Wi-Fi","Wi-Fi 6E"]]'),
(19,'Gigabyte B760M DS3H DDR4 LGA1700','Gigabyte',649,799,'placas-mae',24,4.5,341,'A <strong>Gigabyte B760M DS3H DDR4</strong> é uma placa-mãe Micro-ATX de entrada para Intel 12ª/13ª/14ª geração com suporte a DDR4, ideal para builds de escritório e jogos com custo acessível.','[["Fabricante","Gigabyte"],["Chipset","Intel B760"],["Socket","LGA1700"],["Form Factor","Micro-ATX"],["Memória","4x DDR4, até 128 GB"],["Slots M.2","2x PCIe 4.0"],["Rede","1GbE Realtek"]]'),
(20,'Cooler Master HAF 700 EVO Mid-Tower ARGB','Cooler Master',1299,1599,'gabinetes',5,4.7,93,'O <strong>Cooler Master HAF 700 EVO</strong> é um gabinete Full Tower com três painéis de vidro temperado, suporte a builds de alta performance com até 420 mm de cooler de water, ARGB controlado via software e design icônico.','[["Fabricante","Cooler Master"],["Tipo","Full Tower"],["Material","Aço + Vidro Temperado"],["Suporte a Placas","ATX, E-ATX, Micro-ATX, ITX"],["Bays para HD","2x 3.5\""],["Slots para SSD","4x 2.5\""],["Coolers Pré-instalados","3x 120mm ARGB frontal"],["Suporte Radiador Frontal","até 420 mm"],["Suporte Radiador Superior","até 360 mm"],["Comprimento GPU Máx.","410 mm"],["Altura CPU Cooler Máx.","185 mm"],["Porta Frontal","1x USB 3.2 Gen2 Type-C, 2x USB 3.0, Áudio"]]'),
