(22,'NZXT H9 Flow Mid-Tower Dual-Chamber','NZXT',799,999,'gabinetes',6,4.8,122,'O <strong>NZXT H9 Flow</strong> combina design clean com excelente fluxo de ar graças ao seu painel frontal perfurado e câmara dupla. Suporta radiadores de até 360 mm e GPUs de até 435 mm.','[["Fabricante","NZXT"],["Tipo","Mid Tower"],["Material","Aço + Vidro Temperado"],["Suporte a Placas","ATX, Micro-ATX, ITX"],["Câmara Dupla","Sim"],["Suporte Radiador Frontal","360 mm"],["Comprimento GPU Máx.","435 mm"],["Porta Frontal","1x USB 3.2 Gen2 Type-C, 2x USB 3.0, Áudio"]]'),
